input.command:
kubectl -n cockroachdb patch statefulset crdb-cluster --type='json' -p='[
  {
    "op": "replace",
    "path": "/spec/template/spec/containers/0/command",
    "value": [
      "/cockroach/cockroach",
      "start",
      "--certs-dir=/cockroach/cockroach-certs",
      "--advertise-addr=$(POD_NAME).crdb-cluster.cockroachdb.svc.cluster.local",
      "--http-addr=0.0.0.0",
      "--join=crdb-cluster-0.crdb-cluster.cockroachdb.svc.cluster.local,crdb-cluster-1.crdb-cluster.cockroachdb.svc.cluster.local,crdb-cluster-2.crdb-cluster.cockroachdb.svc.cluster.local",
      "--cache=25%",
      "--max-sql-memory=25%"
    ]
  },
  {
    "op": "replace",
    "path": "/spec/template/spec/containers/0/env/1",
    "value": {
      "name": "COCKROACH_CHANNEL",
      "value": "kubernetes-secure"
    }
  },
  {
    "op": "replace",
    "path": "/spec/template/spec/containers/0/readinessProbe",
    "value": {
      "failureThreshold": 6,
      "httpGet": {
        "path": "/health",
        "port": 8080,
        "scheme": "HTTPS"
      },
      "initialDelaySeconds": 10,
      "periodSeconds": 5,
      "successThreshold": 1,
      "timeoutSeconds": 1
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "certs",
      "mountPath": "/cockroach/cockroach-certs",
      "readOnly": true
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/volumes",
    "value": [
      {
        "name": "certs",
        "secret": {
          "secretName": "crdb-node-certs",
          "defaultMode": 256
        }
      }
    ]
  }
]' 2>&1
